from sentence_transformers import SentenceTransformer, util

def chunk_text(text, max_words=80, overlap=20):
    words = text.split()
    chunks, start = [], 0
    while start < len(words):
        end = min(start + max_words, len(words))
        chunks.append(" ".join(words[start:end]))
        start += max_words - overlap
    return chunks

class ProductionRAG:
    def __init__(self, documents, backend="onnx"):
        kwargs = {"provider": "CPUExecutionProvider"} if backend == "onnx" else {}
        self.model = SentenceTransformer(
            "paraphrase-multilingual-MiniLM-L12-v2",
            backend=backend, model_kwargs=kwargs
        )
        self.chunks, self.sources = [], []
        for i, doc in enumerate(documents):
            doc_chunks = chunk_text(doc)
            self.chunks.extend(doc_chunks)
            self.sources.extend([i] * len(doc_chunks))
        self.embs = self.model.encode(
            self.chunks, normalize_embeddings=True, batch_size=64
        )

    def retrieve(self, query, top_k=3):
        q = self.model.encode(query, normalize_embeddings=True)
        scores = util.cos_sim(q, self.embs)[0]
        ranked = scores.argsort(descending=True).tolist()
        results, seen = [], set()
        for idx in ranked:
            src = self.sources[idx]
            if src in seen:
                continue
            seen.add(src)
            results.append({"chunk": self.chunks[idx], "source": src, "score": float(scores[idx])})
            if len(results) >= top_k:
                break
        return results
